
CREATE TABLE birds (
    id BIGSERIAL primary key,
    name VARCHAR(100),
    sciName VARCHAR(100),
    family VARCHAR(100),
    birdOrder VARCHAR(100),
    status VARCHAR(100),
    lengthMin real,
    lengthMax real,
    wingspanMin real,
    wingspanMax real,
    rarity INTEGER,
    images VARCHAR(100)
);


